document.addEventListener("DOMContentLoaded",()=>{window.lenis=new Lenis({lerp:.1,wheelMultiplier:.7,infinite:!1,gestureOrientation:"vertical",normalizeWheel:!1,smoothTouch:!1}),requestAnimationFrame(function e(i){window.lenis.raf(i),requestAnimationFrame(e)}),window.lenis.on("scroll",ScrollTrigger.update),gsap.ticker.add(e=>{window.lenis.raf(1e3*e)}),gsap.ticker.lagSmoothing(0)});